#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=220,M=N*N;int n,m;
int head[N],nxt[M],des[M],cgt=1,deg[N],stk[M],top;
bool ban[M],dic[M];
vector<int> V;
inline void ins(int x,int y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;
}
inline void dfs(int u)
{
//	printf("dfs %d\n",u);
	for(int &i=head[u];i;i=nxt[i])if(!ban[i>>1])
	{
		int v=des[i];stk[++top]=i;
		dic[i>>1]=i&1;ban[i>>1]=true;dfs(v);
	}
//	if(top)E.push_back(stk[top--]);
}
int main()
{
	int cnt=0;
	int T=read();Begin: 
	
//	printf("Test Case %d :: \n",++cnt);
	n=read();m=read();
	memset(deg,0,(n+1)*sizeof(int));cgt=1;
	memset(head,0,(n+1)*sizeof(int));
//	memset(dic,0,m+1);memset(ban,0,m+1);
	rep(1,m,i)
	{
		int x=read(),y=read();
		++deg[x];++deg[y];ins(x,y);
	}
	V.clear();
	int ans=0;rep(1,n,i)if(deg[i]&1)V.push_back(i);else ++ans;
	for(unsigned i=0;i<V.size();i+=2)ins(V[i],V[i+1]);
	memset(ban,0,(cgt>>1)+10);
	memset(dic,0,(cgt>>1)+10);
	rep(1,n,i)dfs(i),top=0;printf("%d\n",ans);
	rep(1,m,i)
	{
		if(dic[i])printf("%d %d\n",des[i<<1],des[i<<1|1]);
		else printf("%d %d\n",des[i<<1|1],des[i<<1]);
	}
//	puts("<<<<<<");\
//remote judge silly/fn
	if(--T)goto Begin;return 0;
}
